1	/**
2	 * Command palette sources & ranker — spec §18.
3	 *
4	 * Pure-state composition for the §18 cmdk-backed palette: aggregates
5	 * sources (recent / tools / views / elements / settings / agent), parses
6	 * prefix grammar (`>` for tools, `@` for elements, `:` for settings),
7	 * and produces a ranked candidate list. The cmdk widget itself lives in
8	 * `CommandPalette.tsx` and consumes this module.
9	 */
10	
11	export type CommandSourceKind = 'recent' | 'tool' | 'view' | 'element' | 'setting' | 'agent';
12	
13	export interface CommandCandidate {
14	  id: string;
15	  kind: CommandSourceKind;
16	  label: string;
17	  /** Extra free-text keywords appended to the matchable string. */
18	  keywords?: string;
19	  /** Optional shortcut hint shown trailing the label. */
20	  hint?: string;
21	}
22	
23	const PRIORITY: Record<CommandSourceKind, number> = {
24	  recent: 0,
25	  tool: 1,
26	  view: 2,
27	  element: 3,
28	  setting: 4,
29	  agent: 5,
30	};
31	
32	export interface CommandPaletteQuery {
33	  /** Raw query as typed (still includes any prefix). */
34	  raw: string;
35	  /** Parsed source-kind filter — null when no prefix used. */
36	  filter: CommandSourceKind | null;
37	  /** Stripped query without the prefix. */
38	  needle: string;
39	}
40	
41	const PREFIX_MAP: Record<string, CommandSourceKind> = {
42	  '>': 'tool',
43	  '@': 'element',
44	  ':': 'setting',
45	};
46	
47	/** Parse the query string into `{ filter, needle }` per §18 prefix grammar. */
48	export function parseQuery(raw: string): CommandPaletteQuery {
49	  const trimmed = raw.trim();
50	  if (!trimmed) return { raw, filter: null, needle: '' };
51	  const head = trimmed[0]!;
52	  const filter = PREFIX_MAP[head] ?? null;
53	  const needle = filter ? trimmed.slice(1).trim() : trimmed;
54	  return { raw, filter, needle };
55	}
56	
57	function fuzzyScore(haystack: string, needle: string): number | null {
58	  const h = haystack.toLowerCase();
59	  const n = needle.toLowerCase();
60	  if (!n) return 0;
61	  if (h === n) return 1000;
62	  if (h.startsWith(n)) return 800;
63	  if (h.includes(n)) return 600;
64	  // Sequential subsequence match.
65	  let idx = 0;
66	  for (const ch of n) {
67	    const found = h.indexOf(ch, idx);
68	    if (found < 0) return null;
69	    idx = found + 1;
70	  }
71	  return 200;
