765	function CustomTypeForm({
766	  discipline,
767	  onSave,
768	  onCancel,
769	}: {
770	  discipline: 'door' | 'window';
771	  onSave: (baseFamilyId: string, name: string, params: Record<string, unknown>) => void;
772	  onCancel: () => void;
773	}): JSX.Element {
774	  const families = BUILT_IN_FAMILIES.filter((f) => f.discipline === discipline);
775	  const [baseFamilyId, setBaseFamilyId] = useState(families[0]?.id ?? '');
776	  const [name, setName] = useState('');
777	  const [paramDraft, setParamDraft] = useState<Record<string, string>>({});
778	
779	  const baseFam = getFamilyById(baseFamilyId);
780	  const lengthParams = baseFam?.params.filter((p) => p.type === 'length_mm') ?? [];
781	
782	  function handleSave(): void {
783	    const params: Record<string, unknown> = { name: name.trim(), baseFamilyId };
784	    for (const p of lengthParams) {
785	      const raw = paramDraft[p.key];
786	      const val = raw !== undefined ? Number(raw) : (p.default as number);
787	      if (Number.isFinite(val)) params[p.key] = val;
788	    }
789	    onSave(baseFamilyId, name.trim(), params);
790	  }
791	
792	  return (
793	    <div className="mt-1 space-y-1.5 rounded border border-border bg-background p-2">
794	      <label className={LABEL_CLS}>
795	        Base family
796	        <select
797	          className={INPUT_CLS}
798	          value={baseFamilyId}
799	          onChange={(e) => {
800	            setBaseFamilyId(e.target.value);
801	            setParamDraft({});
802	          }}
803	        >
804	          {families.map((f) => (
805	            <option key={f.id} value={f.id}>
806	              {f.name}
807	            </option>
808	          ))}
809	        </select>
810	      </label>
811	      <label className={LABEL_CLS}>
812	        Type name
813	        <input
814	          className={INPUT_CLS}
815	          value={name}
816	          onChange={(e) => setName(e.target.value)}
817	          placeholder="e.g. Wide fire door"
818	          autoFocus
819	        />
820	      </label>
821	      {lengthParams.map((p) => (
822	        <label key={p.key} className={LABEL_CLS}>
823	          {p.label} (mm)
824	          <input
825	            className={INPUT_CLS}
826	            type="number"
827	            value={paramDraft[p.key] ?? String(p.default as number)}
828	            onChange={(e) => setParamDraft((d) => ({ ...d, [p.key]: e.target.value }))}
829	          />
830	        </label>
831	      ))}
