      kind: 'railing',
      id: 'thumb-railing',
      name: 'thumb-railing',
      pathMm: [
        { xMm: 0, yMm: 0 },
        { xMm: 2400, yMm: 0 },
      ],
      guardHeightMm: Number(builtin.parameters.guardHeightMm ?? 1050),
      overrideParams: { familyTypeId: builtin.id },
    } as Extract<Element, { kind: 'railing' }>;
    return buildRailingGeometry({
      railing,
      baseElevM: 0,
      topElevM: 0,
      paint: null,
      familyDef: family,
    });
